package arch.day21;

public class Day21Basic {
    static class Node {
        int v;
        Node next;
        Node(int v, Node next) { this.v = v; this.next = next; }
    }

    public static void main(String[] args) {
        Node head = new Node(1, new Node(2, new Node(3, null)));
        Node c = head;
        while (c != null) {
            System.out.print(c.v + " ");
            c = c.next;
        }
        System.out.println();
    }
}

package arch.day21;

public class Day21Intermediate {
    static class Node {
        int v;
        Node next;
        Node(int v) { this.v = v; }
    }

    static Node reverse(Node head) {
        Node prev = null, cur = head;
        while (cur != null) {
            Node n = cur.next;
            cur.next = prev;
            prev = cur;
            cur = n;
        }
        return prev;
    }

    public static void main(String[] args) {
        Node a = new Node(1), b = new Node(2), c = new Node(3);
        a.next = b; b.next = c;
        Node h = reverse(a);
        System.out.println(h.v + "->" + h.next.v + "->" + h.next.next.v);
    }
}

package arch.day21;

public class Day21Advanced {
    static class Node {
        int v;
        Node next;
        Node(int v) { this.v = v; }
    }

    static boolean hasCycle(Node head) {
        Node s = head, f = head;
        while (f != null && f.next != null) {
            s = s.next;
            f = f.next.next;
            if (s == f) return true;
        }
        return false;
    }

    public static void main(String[] args) {
        Node a = new Node(1), b = new Node(2);
        a.next = b; b.next = a;
        System.out.println(hasCycle(a));
    }
}

